  templateUrl: './sidebar.component.html',
  styleUrl: './sidebar.component.scss',
})
export class SidebarComponent {
  items = input<ISidebarItem[]>([]);
  collapsed = model<boolean>(false);
  activeRoute = input<string>('');
  mobileOpen = model<boolean>(false);

  itemClick = output<ISidebarItem>();
  toggleCollapse = output<void>();

  toggleCollapsed(): void {
    this.collapsed.update(v => !v);
    this.toggleCollapse.emit();
  }

  closeMobile(): void {
    this.mobileOpen.set(false);
  }

  onItemClick(item: ISidebarItem): void {
    this.itemClick.emit(item);
    if (this.mobileOpen()) {
      this.closeMobile();
    }
  }

  isActive(route: string): boolean {
    return this.activeRoute() === route;
  }

  trackByRoute(index: number, item: ISidebarItem): string {
    return item.isHeader ? `header-${index}-${item.label}` : item.route;
  }
}

import { ISelectOption } from '../../../shared/components/select/select.component';

export interface ITicketAttachment {
  id: string;
  name: string;
  size: number;
  type: string;
  previewUrl?: string;
}

export interface ITicket {
  id: string;
  title: string;
  category: 'bug' | 'improvement' | 'question' | 'other';
  priority: 'low' | 'medium' | 'high' | 'critical';
  affectedModule: string;
  description: string;
  attachments: ITicketAttachment[];
  status: 'open' | 'in_analysis' | 'resolved' | 'closed';
  createdAt: string;
  createdBy: string;
  browserInfo: string;
  screenResolution: string;
}

export const MOCK_CATEGORIES: ISelectOption[] = [
  { value: 'bug', label: 'Bug — Algo não está funcionando' },
  { value: 'improvement', label: 'Melhoria — Sugestão de melhoria' },
  { value: 'question', label: 'Dúvida — Preciso de ajuda' },
  { value: 'other', label: 'Outro' },
