import { Component, computed, inject, input, signal, OnInit } from '@angular/core';
import { ActivatedRoute, Router, RouterOutlet, NavigationEnd, Event as RouterEvent } from '@angular/router';
import { filter } from 'rxjs/operators';
import { HeaderComponent } from '../header/header.component';
import { SidebarComponent } from '../../shared/components/sidebar/sidebar.component';
import { FooterComponent } from '../footer/footer.component';

@Component({
  selector: 'app-main-layout',
  standalone: true,
  imports: [RouterOutlet, HeaderComponent, SidebarComponent, FooterComponent],
  templateUrl: './main-layout.component.html',
  styleUrl: './main-layout.component.scss'
})
export class MainLayoutComponent implements OnInit {
  private router = inject(Router);
  private route = inject(ActivatedRoute);

  // Sidebar types
  private readonly emptySidebarItems: { icon: string; label: string; route: string; badge?: string }[] = [];

  // Inputs
  sidebarItems = input<{ icon: string; label: string; route: string; badge?: string }[]>([]);
  sidebarActiveRoute = input<string>('');

  // Signals
  sidebarCollapsed = signal<boolean>(false);
  sidebarMobileOpen = signal<boolean>(false);
  isMobile = signal<boolean>(false);
  routeSidebarItems = signal<{ icon: string; label: string; route: string; badge?: string }[]>([]);
  routeSidebarActiveRoute = signal<string>('');

  // Computed
  resolvedSidebarItems = computed(() => this.sidebarItems().length > 0 ? this.sidebarItems() : this.routeSidebarItems());
  resolvedSidebarActiveRoute = computed(() => this.sidebarActiveRoute() || this.routeSidebarActiveRoute());

  showSidebar = computed(() => this.resolvedSidebarItems().length > 0 || this.isMobile());
  effectiveSidebarItems = computed(() => {
    if (this.isMobile()) {
      const items: { icon: string; label: string; route: string; badge?: string; isHeader?: boolean }[] = [];
      const navs = this.navItems();
      const sidebars = this.resolvedSidebarItems();

      if (navs.length > 0) {
        items.push({ label: 'Módulos', route: '', icon: '', isHeader: true });
        items.push(...navs);
      }

      if (sidebars.length > 0) {
        items.push({ label: 'Menu da Página', route: '', icon: '', isHeader: true });
        items.push(...sidebars);
      }

      return items;
    }
    return this.resolvedSidebarItems();
  });

  // Header Mock Data
  navItems = signal([
    { label: 'Dashboard', route: '/dashboard', icon: 'layout-dashboard' },
    { label: 'Tarefas', route: '/tarefas', icon: 'clipboard-list' },
    { label: 'Clientes', route: '/clientes', icon: 'building-2' },
    { label: 'Equipe', route: '/equipe', icon: 'users' }
  ]);
  userName = signal('Sirlene Sales');
  userAvatar = signal('');
  logoSrc = signal('logo.webp');
  activeRoute = signal<string>('');

  ngOnInit() {
    this.updateActiveRoute(this.router.url);
    this.updateSidebarFromRoute();

    this.router.events.pipe(
      filter((event: RouterEvent): event is NavigationEnd => event instanceof NavigationEnd)
    ).subscribe((event: NavigationEnd) => {
      this.updateActiveRoute(event.urlAfterRedirects);
      this.updateSidebarFromRoute();
    });

    this.checkResponsive();
    window.addEventListener('resize', this.checkResponsive.bind(this));
  }

  updateActiveRoute(url: string) {
    // Basic active route matching for the header
    const cleanUrl = url.split('?')[0];
    const segments = cleanUrl.split('/').filter(s => s);
    this.activeRoute.set(segments.length > 0 ? '/' + segments[0] : '/dashboard');
    this.routeSidebarActiveRoute.set(cleanUrl || '/dashboard');
  }

  updateSidebarFromRoute(): void {
    let current = this.route.firstChild;
    let sidebarItems = this.emptySidebarItems;

    while (current) {
      const data = current.snapshot.data as { sidebarItems?: { icon: string; label: string; route: string; badge?: string }[] };
      if (data?.sidebarItems) {
        sidebarItems = data.sidebarItems;
      }
      current = current.firstChild;
    }

    this.routeSidebarItems.set(sidebarItems);
  }

  checkResponsive() {
    const width = window.innerWidth;
    this.isMobile.set(width < 768);

    if (width > 1024) {
      this.sidebarCollapsed.set(false);
      this.sidebarMobileOpen.set(false);
    } else if (width >= 768 && width <= 1024) {
      this.sidebarCollapsed.set(true);
      this.sidebarMobileOpen.set(false);
    } else {
      this.sidebarCollapsed.set(false);
    }
  }

  onHeaderNavigate(route: string) {
    this.router.navigate([route]);
  }

  onProfileClick(): void {
    this.router.navigate(['/perfil']);
  }

  onSupportClick(): void {
    this.router.navigate(['/suporte']);
  }

  onMenuClick() {
    this.sidebarMobileOpen.update(v => !v);
  }

  onSidebarNavigate(route: string) {
    this.router.navigate([route]);
    if (window.innerWidth < 768) {
      this.sidebarMobileOpen.set(false);
    }
  }

  toggleSidebar() {
    this.sidebarCollapsed.update(v => !v);
  }
}

import { Component, computed, contentChild, DestroyRef, effect, ElementRef, HostListener, inject, input, output, untracked } from '@angular/core';
import { NgClass } from '@angular/common';
import { LucideAngularModule, LUCIDE_ICONS, LucideIconProvider, X, AlertTriangle, UserCheck } from 'lucide-angular';
import { ButtonComponent } from '../button/button.component';
import { ModalFooterDirective } from './modal-footer.directive';

export type ModalSize = 'sm' | 'md' | 'lg';

const FOCUSABLE_SELECTORS = 'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])';

@Component({
  selector: 'app-modal',
  standalone: true,
  imports: [NgClass, LucideAngularModule, ButtonComponent],
  viewProviders: [
    { provide: LUCIDE_ICONS, useValue: new LucideIconProvider({ X, AlertTriangle, UserCheck }), multi: true },
  ],
  templateUrl: './modal.component.html',
  styleUrl: './modal.component.scss',
})
export class ModalComponent {
  private readonly el = inject(ElementRef);
  private readonly destroyRef = inject(DestroyRef);

  isOpen = input<boolean>(false);
  title = input<string>('');
  size = input<ModalSize>('md');
  closeOnOverlay = input<boolean>(true);
  closeOnEscape = input<boolean>(true);
  showCloseButton = input<boolean>(true);

  closed = output<void>();

  footerContent = contentChild(ModalFooterDirective);
  hasFooter = computed(() => !!this.footerContent());

  constructor() {
    effect(() => {
      const open = this.isOpen();
      untracked(() => {
        document.body.style.overflow = open ? 'hidden' : '';
        if (open) {
          setTimeout(() => {
            const focusableEls = this.el.nativeElement.querySelectorAll(FOCUSABLE_SELECTORS) as NodeListOf<HTMLElement>;
            if (focusableEls.length > 0) {
              focusableEls[0].focus();
            }
          }, 0);
        }
      });
    });

    this.destroyRef.onDestroy(() => {
      document.body.style.overflow = '';
    });
  }

  @HostListener('document:keydown.escape')
  onEscape(): void {
    if (this.isOpen() && this.closeOnEscape()) {
      this.close();
    }
  }

  onOverlayClick(event: MouseEvent | KeyboardEvent): void {
    if (event.target === event.currentTarget && this.closeOnOverlay()) {
      this.close();
    }
  }

  trapFocus(event: KeyboardEvent): void {
    if (event.key !== 'Tab') {
      return;
    }

    const focusableEls = Array.from(
      this.el.nativeElement.querySelectorAll(FOCUSABLE_SELECTORS) as NodeListOf<HTMLElement>
    );

    if (focusableEls.length === 0) {
      event.preventDefault();
      return;
    }

    const firstEl = focusableEls[0];
    const lastEl = focusableEls[focusableEls.length - 1];

    if (event.shiftKey) {
      if (document.activeElement === firstEl) {
        event.preventDefault();
        lastEl.focus();
      }
    } else {
      if (document.activeElement === lastEl) {
        event.preventDefault();
        firstEl.focus();
      }
    }
  }

  close(): void {
    this.closed.emit();
  }
}

